from qdrant_client import QdrantClient
from qdrant_client.models import (
    Distance, VectorParams, PointStruct, Filter, FieldCondition, MatchValue
)
import numpy as np

client = QdrantClient("localhost", port=6333)
COLLECTION = "product_images"

# Create collection (run once)
client.recreate_collection(
    collection_name=COLLECTION,
    vectors_config=VectorParams(size=512, distance=Distance.COSINE),
)

# Index: upsert vectors with payload metadata
def index_products(embeddings: np.ndarray, metadata: list[dict]):
    points = [
        PointStruct(
            id=i,
            vector=embeddings[i].tolist(),
            payload=metadata[i],    # {"category": "shoes", "in_stock": True, "url": "..."}
        )
        for i in range(len(embeddings))
    ]
    client.upsert(collection_name=COLLECTION, points=points)

# Query: text search filtered by category and stock
def search_text_filtered(query_vec: np.ndarray, category: str, k: int = 10):
    return client.search(
        collection_name=COLLECTION,
        query_vector=query_vec[0].tolist(),
        query_filter=Filter(
            must=[
                FieldCondition(key="category", match=MatchValue(value=category)),
                FieldCondition(key="in_stock", match=MatchValue(value=True)),
            ]
        ),
        limit=k,
        with_payload=True,
    )
